// ============================================================================
// TPM 2.0 Protocol Constants
// ============================================================================

/// TPM2_ST_NO_SESSIONS — command with no authorization
const TPM2_ST_NO_SESSIONS: u16 = 0x8001;
/// TPM2_ST_SESSIONS — command with authorization sessions
const TPM2_ST_SESSIONS: u16 = 0x8002;

/// TPM2_CC command codes
const TPM2_CC_CREATE: u32 = 0x00000153;
const TPM2_CC_LOAD: u32 = 0x00000157;
const TPM2_CC_SIGN: u32 = 0x0000015D;
const TPM2_CC_FLUSH_CONTEXT: u32 = 0x00000165;
const TPM2_CC_READ_PUBLIC: u32 = 0x00000173;
const TPM2_CC_GET_CAPABILITY: u32 = 0x0000017A;

/// TPM2_RC_SUCCESS
const TPM2_RC_SUCCESS: u32 = 0x00000000;

/// TPM_RS_PW — password authorization session handle
const TPM_RS_PW: u32 = 0x40000009;

/// TPM_RH_NULL — null hierarchy
const TPM_RH_NULL: u32 = 0x40000007;

/// TPM2_ST_HASHCHECK — hash check ticket tag
const TPM2_ST_HASHCHECK: u16 = 0x8024;

/// TPM2 algorithm identifiers
const TPM2_ALG_RSA: u16 = 0x0001;
const TPM2_ALG_SHA256: u16 = 0x000B;
const TPM2_ALG_SHA384: u16 = 0x000C;
const TPM2_ALG_NULL: u16 = 0x0010;
const TPM2_ALG_RSASSA: u16 = 0x0014;
const TPM2_ALG_ECDSA: u16 = 0x0018;
const TPM2_ALG_ECC: u16 = 0x0023;

/// TPM2 ECC curve identifiers
const TPM2_ECC_NIST_P256: u16 = 0x0003;
const TPM2_ECC_NIST_P384: u16 = 0x0004;

/// TPM2 object attributes
const TPMA_OBJ_FIXED_TPM: u32 = 0x00000002;
const TPMA_OBJ_FIXED_PARENT: u32 = 0x00000010;
const TPMA_OBJ_SENSITIVE_DATA_ORIGIN: u32 = 0x00000020;
const TPMA_OBJ_USER_WITH_AUTH: u32 = 0x00000040;
const TPMA_OBJ_SIGN_ENCRYPT: u32 = 0x00040000;

/// Signing key attributes: generated by TPM, bound to parent, password auth, signing
const SIGN_KEY_ATTRS: u32 = TPMA_OBJ_FIXED_TPM
    | TPMA_OBJ_FIXED_PARENT
    | TPMA_OBJ_SENSITIVE_DATA_ORIGIN
    | TPMA_OBJ_USER_WITH_AUTH
    | TPMA_OBJ_SIGN_ENCRYPT;

/// TPM capability for properties
const TPM2_CAP_TPM_PROPERTIES: u32 = 0x00000006;
/// TPM property: manufacturer ID
const TPM2_PT_MANUFACTURER: u32 = 0x00000105;

/// Maximum response buffer
const TPM2_MAX_RESPONSE: usize = 4096;
/// Header size (tag + size + code)
const TPM2_HEADER_SIZE: usize = 10;

/// Default SRK handle (TCG provisioned)
pub const DEFAULT_SRK_HANDLE: u32 = 0x81000001;

/// TPM device paths in preference order
pub const TPM_DEVICE_PATHS: &[&str] = &["/dev/tpmrm0", "/dev/tpm0"];

// ============================================================================
// DER Encoding Constants (OIDs)
// ============================================================================

/// OID for ecPublicKey (1.2.840.10045.2.1)
const OID_EC_PUBLIC_KEY: &[u8] = &[0x06, 0x07, 0x2A, 0x86, 0x48, 0xCE, 0x3D, 0x02, 0x01];
/// OID for secp256r1 (1.2.840.10045.3.1.7)
const OID_SECP256R1: &[u8] = &[0x06, 0x08, 0x2A, 0x86, 0x48, 0xCE, 0x3D, 0x03, 0x01, 0x07];
/// OID for secp384r1 (1.3.132.0.34)
const OID_SECP384R1: &[u8] = &[0x06, 0x05, 0x2B, 0x81, 0x04, 0x00, 0x22];
/// OID for rsaEncryption (1.2.840.113549.1.1.1)
const OID_RSA_ENCRYPTION: &[u8] = &[
    0x06, 0x09, 0x2A, 0x86, 0x48, 0x86, 0xF7, 0x0D, 0x01, 0x01, 0x01,
];

// ============================================================================
// TPM2 Low-Level I/O
// ============================================================================

/// Write data to a file with restrictive permissions (0600 — owner read/write only).
/// Used for TPM key blobs and metadata to prevent unauthorized access.
#[cfg(unix)]
fn write_restricted(path: &Path, data: &[u8]) -> std::io::Result<()> {
    use std::os::unix::fs::OpenOptionsExt;
    let mut file = OpenOptions::new()
        .write(true)
        .create(true)
        .truncate(true)
        .mode(0o600)
        .open(path)?;
    file.write_all(data)
}

#[cfg(not(unix))]
fn write_restricted(path: &Path, data: &[u8]) -> std::io::Result<()> {
    fs::write(path, data)
}

/// Open TPM device for read/write
fn open_tpm_device(path: &str) -> Result<File, KeyStoreError> {
    OpenOptions::new()
        .read(true)
        .write(true)
        .open(path)
        .map_err(|e| {
            if e.kind() == std::io::ErrorKind::PermissionDenied {
                KeyStoreError::AuthenticationFailed(format!(
                    "TPM access denied: {}. Add user to 'tss' group or run as root",
                    e
                ))
            } else {
                KeyStoreError::ConnectionError(format!("Failed to open TPM device {}: {}", path, e))
            }
        })
}

/// Execute a raw TPM command and return the response
fn execute_command(device: &mut File, command: &[u8]) -> KeyStoreResult<Vec<u8>> {
    device
        .write_all(command)
        .map_err(|e| KeyStoreError::ConnectionError(format!("TPM write failed: {}", e)))?;
    device
        .flush()
        .map_err(|e| KeyStoreError::ConnectionError(format!("TPM flush failed: {}", e)))?;

    let mut response = vec![0u8; TPM2_MAX_RESPONSE];
    let n = device
        .read(&mut response)
        .map_err(|e| KeyStoreError::ConnectionError(format!("TPM read failed: {}", e)))?;

    if n < TPM2_HEADER_SIZE {
        return Err(KeyStoreError::Internal(format!(
            "TPM response too short: {} bytes",
            n
        )));
    }

    response.truncate(n);
    Ok(response)
}

/// Parse response header → (tag, size, response_code)
fn parse_response_header(response: &[u8]) -> KeyStoreResult<(u16, u32, u32)> {
    if response.len() < TPM2_HEADER_SIZE {
        return Err(KeyStoreError::Internal("TPM response too short".into()));
    }
    let tag = u16::from_be_bytes([response[0], response[1]]);
    let size = u32::from_be_bytes([response[2], response[3], response[4], response[5]]);
    let code = u32::from_be_bytes([response[6], response[7], response[8], response[9]]);
    Ok((tag, size, code))
}

/// Check response code and return descriptive error if non-zero
fn check_response(response: &[u8], command_name: &str) -> KeyStoreResult<()> {
    let (_tag, _size, code) = parse_response_header(response)?;
    if code != TPM2_RC_SUCCESS {
        return Err(KeyStoreError::Internal(format!(
            "{} failed: TPM error 0x{:08X}",
            command_name, code
        )));
    }
    Ok(())
}

// ============================================================================
// TPM2 Authorization Session Builder
// ============================================================================

/// Build a password authorization area with empty password (for SRK default auth)
fn build_empty_password_auth() -> Vec<u8> {
    let mut auth = Vec::with_capacity(9);
    // Session handle: TPM_RS_PW (password session)
    auth.extend_from_slice(&TPM_RS_PW.to_be_bytes());
    // Nonce caller: empty TPM2B
    auth.extend_from_slice(&0u16.to_be_bytes());
    // Session attributes: continueSession
    auth.push(0x01);
    // HMAC/password: empty TPM2B
    auth.extend_from_slice(&0u16.to_be_bytes());
    auth
}

// ============================================================================
// TPM2 Command Builders
// ============================================================================

/// Build TPM2_Create command for an ECC signing key
fn build_create_ecc_command(parent_handle: u32, curve: u16, hash_alg: u16) -> Vec<u8> {
    let auth = build_empty_password_auth();

    // inSensitive: TPM2B_SENSITIVE_CREATE { userAuth: empty, data: empty }
    let in_sensitive: &[u8] = &[0x00, 0x04, 0x00, 0x00, 0x00, 0x00];

    // inPublic: TPMT_PUBLIC for ECC signing key
    let mut public_area = Vec::new();
    public_area.extend_from_slice(&TPM2_ALG_ECC.to_be_bytes()); // type
    public_area.extend_from_slice(&hash_alg.to_be_bytes()); // nameAlg
    public_area.extend_from_slice(&SIGN_KEY_ATTRS.to_be_bytes()); // objectAttributes
    public_area.extend_from_slice(&0u16.to_be_bytes()); // authPolicy: empty
                                                        // parameters: TPMS_ECC_PARMS
    public_area.extend_from_slice(&TPM2_ALG_NULL.to_be_bytes()); // symmetric: NULL
    public_area.extend_from_slice(&TPM2_ALG_ECDSA.to_be_bytes()); // scheme: ECDSA
    public_area.extend_from_slice(&hash_alg.to_be_bytes()); // scheme.hashAlg
    public_area.extend_from_slice(&curve.to_be_bytes()); // curveID
    public_area.extend_from_slice(&TPM2_ALG_NULL.to_be_bytes()); // kdf: NULL
                                                                 // unique: TPMS_ECC_POINT { x: empty, y: empty }
    public_area.extend_from_slice(&0u16.to_be_bytes()); // x size
    public_area.extend_from_slice(&0u16.to_be_bytes()); // y size

    // Wrap in TPM2B_PUBLIC
    let public_size = public_area.len() as u16;

    // outsideInfo: empty, creationPCR: count=0
    let trailing: &[u8] = &[0x00, 0x00, 0x00, 0x00, 0x00, 0x00];

    // Calculate total command size
    let body_size =
        4 + 4 + auth.len() + in_sensitive.len() + 2 + public_area.len() + trailing.len();
    let total_size = (TPM2_HEADER_SIZE + body_size) as u32;

    let mut cmd = Vec::with_capacity(total_size as usize);
    // Header
    cmd.extend_from_slice(&TPM2_ST_SESSIONS.to_be_bytes());
    cmd.extend_from_slice(&total_size.to_be_bytes());
    cmd.extend_from_slice(&TPM2_CC_CREATE.to_be_bytes());
    // Parent handle
    cmd.extend_from_slice(&parent_handle.to_be_bytes());
    // Authorization size + auth area
    cmd.extend_from_slice(&(auth.len() as u32).to_be_bytes());
    cmd.extend_from_slice(&auth);
    // inSensitive
    cmd.extend_from_slice(in_sensitive);
    // inPublic (size prefix + area)
    cmd.extend_from_slice(&public_size.to_be_bytes());
    cmd.extend_from_slice(&public_area);
    // outsideInfo + creationPCR
    cmd.extend_from_slice(trailing);

    cmd
}

/// Build TPM2_Create command for an RSA signing key
fn build_create_rsa_command(parent_handle: u32, key_bits: u16) -> Vec<u8> {
    let auth = build_empty_password_auth();

    // inSensitive: empty
    let in_sensitive: &[u8] = &[0x00, 0x04, 0x00, 0x00, 0x00, 0x00];

    // inPublic: TPMT_PUBLIC for RSA signing key
    let mut public_area = Vec::new();
    public_area.extend_from_slice(&TPM2_ALG_RSA.to_be_bytes()); // type
    public_area.extend_from_slice(&TPM2_ALG_SHA256.to_be_bytes()); // nameAlg
    public_area.extend_from_slice(&SIGN_KEY_ATTRS.to_be_bytes()); // objectAttributes
    public_area.extend_from_slice(&0u16.to_be_bytes()); // authPolicy: empty
                                                        // parameters: TPMS_RSA_PARMS
    public_area.extend_from_slice(&TPM2_ALG_NULL.to_be_bytes()); // symmetric: NULL
    public_area.extend_from_slice(&TPM2_ALG_RSASSA.to_be_bytes()); // scheme: RSASSA
    public_area.extend_from_slice(&TPM2_ALG_SHA256.to_be_bytes()); // scheme.hashAlg
    public_area.extend_from_slice(&key_bits.to_be_bytes()); // keyBits
    public_area.extend_from_slice(&0u32.to_be_bytes()); // exponent: 0 = default 65537
                                                        // unique: TPM2B_PUBLIC_KEY_RSA { size: 0 }
    public_area.extend_from_slice(&0u16.to_be_bytes());

    let public_size = public_area.len() as u16;

    // outsideInfo: empty, creationPCR: count=0
    let trailing: &[u8] = &[0x00, 0x00, 0x00, 0x00, 0x00, 0x00];

    let body_size =
        4 + 4 + auth.len() + in_sensitive.len() + 2 + public_area.len() + trailing.len();
    let total_size = (TPM2_HEADER_SIZE + body_size) as u32;

    let mut cmd = Vec::with_capacity(total_size as usize);
    cmd.extend_from_slice(&TPM2_ST_SESSIONS.to_be_bytes());
    cmd.extend_from_slice(&total_size.to_be_bytes());
    cmd.extend_from_slice(&TPM2_CC_CREATE.to_be_bytes());
    cmd.extend_from_slice(&parent_handle.to_be_bytes());
    cmd.extend_from_slice(&(auth.len() as u32).to_be_bytes());
    cmd.extend_from_slice(&auth);
    cmd.extend_from_slice(in_sensitive);
    cmd.extend_from_slice(&public_size.to_be_bytes());
    cmd.extend_from_slice(&public_area);
    cmd.extend_from_slice(trailing);

    cmd
}

/// Parse TPM2_Create response → (out_private, out_public)
///
/// Response layout (after header):
///   parameterSize(4) + outPrivate(TPM2B) + outPublic(TPM2B) + creation data + auth
fn parse_create_response(response: &[u8]) -> KeyStoreResult<(Vec<u8>, Vec<u8>)> {
    check_response(response, "TPM2_Create")?;

    let mut offset = TPM2_HEADER_SIZE;

    // parameterSize (4 bytes)
    if response.len() < offset + 4 {
        return Err(KeyStoreError::Internal(
            "Create response: missing parameterSize".into(),
        ));
    }
    offset += 4;

    // outPrivate: TPM2B_PRIVATE (2 byte size + data)
    if response.len() < offset + 2 {
        return Err(KeyStoreError::Internal(
            "Create response: missing outPrivate size".into(),
        ));
    }
    let priv_size = u16::from_be_bytes([response[offset], response[offset + 1]]) as usize;
    offset += 2;
    if response.len() < offset + priv_size {
        return Err(KeyStoreError::Internal(
            "Create response: outPrivate truncated".into(),
        ));
    }
    // Include the size prefix in the blob for re-use in TPM2_Load
    let out_private = response[offset - 2..offset + priv_size].to_vec();
    offset += priv_size;

    // outPublic: TPM2B_PUBLIC (2 byte size + data)
    if response.len() < offset + 2 {
        return Err(KeyStoreError::Internal(
            "Create response: missing outPublic size".into(),
        ));
    }
    let pub_size = u16::from_be_bytes([response[offset], response[offset + 1]]) as usize;
    if response.len() < offset + 2 + pub_size {
        return Err(KeyStoreError::Internal(
            "Create response: outPublic truncated".into(),
        ));
    }
    let out_public = response[offset..offset + 2 + pub_size].to_vec();

    Ok((out_private, out_public))
}

/// Build TPM2_Load command
fn build_load_command(parent_handle: u32, private_blob: &[u8], public_blob: &[u8]) -> Vec<u8> {
    let auth = build_empty_password_auth();

    let body_size = 4 + 4 + auth.len() + private_blob.len() + public_blob.len();
    let total_size = (TPM2_HEADER_SIZE + body_size) as u32;

    let mut cmd = Vec::with_capacity(total_size as usize);
    cmd.extend_from_slice(&TPM2_ST_SESSIONS.to_be_bytes());
    cmd.extend_from_slice(&total_size.to_be_bytes());
    cmd.extend_from_slice(&TPM2_CC_LOAD.to_be_bytes());
    cmd.extend_from_slice(&parent_handle.to_be_bytes());
    cmd.extend_from_slice(&(auth.len() as u32).to_be_bytes());
    cmd.extend_from_slice(&auth);
    cmd.extend_from_slice(private_blob);
    cmd.extend_from_slice(public_blob);

    cmd
}

/// Parse TPM2_Load response → loaded object handle
///
/// Response layout: header(10) + handle(4) + parameterSize(4) + name(TPM2B) + auth
fn parse_load_response(response: &[u8]) -> KeyStoreResult<u32> {
    check_response(response, "TPM2_Load")?;

    if response.len() < TPM2_HEADER_SIZE + 4 {
        return Err(KeyStoreError::Internal(
            "Load response: missing object handle".into(),
        ));
    }

    let handle = u32::from_be_bytes([
        response[TPM2_HEADER_SIZE],
        response[TPM2_HEADER_SIZE + 1],
        response[TPM2_HEADER_SIZE + 2],
        response[TPM2_HEADER_SIZE + 3],
    ]);

    Ok(handle)
}

/// Build TPM2_Sign command
///
/// The digest must be pre-hashed to match the scheme's hash algorithm.
fn build_sign_command(key_handle: u32, digest: &[u8], sig_alg: u16, hash_alg: u16) -> Vec<u8> {
    let auth = build_empty_password_auth();

    // TPM2B_DIGEST
    let digest_size = digest.len() as u16;

    // TPMT_SIG_SCHEME: { scheme, hashAlg }
    // TPMT_TK_HASHCHECK: { tag, hierarchy, digest(empty) }
    let validation_size = 2 + 4 + 2; // tag(2) + hierarchy(4) + empty digest size(2)

    let body_size = 4 + 4 + auth.len() + 2 + digest.len() + 2 + 2 + validation_size;
    let total_size = (TPM2_HEADER_SIZE + body_size) as u32;

    let mut cmd = Vec::with_capacity(total_size as usize);
    cmd.extend_from_slice(&TPM2_ST_SESSIONS.to_be_bytes());
    cmd.extend_from_slice(&total_size.to_be_bytes());
    cmd.extend_from_slice(&TPM2_CC_SIGN.to_be_bytes());
    cmd.extend_from_slice(&key_handle.to_be_bytes());
    cmd.extend_from_slice(&(auth.len() as u32).to_be_bytes());
    cmd.extend_from_slice(&auth);
    // digest
    cmd.extend_from_slice(&digest_size.to_be_bytes());
    cmd.extend_from_slice(digest);
    // inScheme
    cmd.extend_from_slice(&sig_alg.to_be_bytes());
    cmd.extend_from_slice(&hash_alg.to_be_bytes());
    // validation ticket (NULL ticket)
    cmd.extend_from_slice(&TPM2_ST_HASHCHECK.to_be_bytes());
    cmd.extend_from_slice(&TPM_RH_NULL.to_be_bytes());
    cmd.extend_from_slice(&0u16.to_be_bytes()); // empty digest

    cmd
}

/// Parse TPM2_Sign response for ECDSA → DER-encoded signature
///
/// Response: header + parameterSize + TPMT_SIGNATURE { sigAlg, hashAlg, r(TPM2B), s(TPM2B) } + auth
fn parse_ecdsa_sign_response(response: &[u8]) -> KeyStoreResult<Vec<u8>> {
    check_response(response, "TPM2_Sign")?;

    let mut offset = TPM2_HEADER_SIZE + 4; // skip parameterSize

    // sigAlg (2 bytes)
    if response.len() < offset + 2 {
        return Err(KeyStoreError::Internal(
            "Sign response: missing sigAlg".into(),
        ));
    }
    offset += 2; // skip sigAlg

    // hashAlg (2 bytes)
    if response.len() < offset + 2 {
        return Err(KeyStoreError::Internal(
            "Sign response: missing hashAlg".into(),
        ));
    }
    offset += 2; // skip hashAlg

    // signatureR: TPM2B_ECC_PARAMETER
    if response.len() < offset + 2 {
        return Err(KeyStoreError::Internal(
            "Sign response: missing r size".into(),
        ));
    }
    let r_size = u16::from_be_bytes([response[offset], response[offset + 1]]) as usize;
    offset += 2;
    if response.len() < offset + r_size {
        return Err(KeyStoreError::Internal("Sign response: r truncated".into()));
    }
    let r = &response[offset..offset + r_size];
    offset += r_size;

    // signatureS: TPM2B_ECC_PARAMETER
    if response.len() < offset + 2 {
        return Err(KeyStoreError::Internal(
            "Sign response: missing s size".into(),
        ));
    }
    let s_size = u16::from_be_bytes([response[offset], response[offset + 1]]) as usize;
    offset += 2;
    if response.len() < offset + s_size {
        return Err(KeyStoreError::Internal("Sign response: s truncated".into()));
    }
    let s = &response[offset..offset + s_size];

    // Convert (r, s) to DER: SEQUENCE { INTEGER r, INTEGER s }
    Ok(ecdsa_rs_to_der(r, s))
}

/// Parse TPM2_Sign response for RSA → raw signature bytes
///
/// Response: header + parameterSize + TPMT_SIGNATURE { sigAlg, hashAlg, sig(TPM2B) } + auth
fn parse_rsa_sign_response(response: &[u8]) -> KeyStoreResult<Vec<u8>> {
    check_response(response, "TPM2_Sign")?;

    let mut offset = TPM2_HEADER_SIZE + 4; // skip parameterSize

    // sigAlg + hashAlg (4 bytes)
    offset += 4;

    // sig: TPM2B_PUBLIC_KEY_RSA
    if response.len() < offset + 2 {
        return Err(KeyStoreError::Internal(
            "Sign response: missing sig size".into(),
        ));
    }
    let sig_size = u16::from_be_bytes([response[offset], response[offset + 1]]) as usize;
    offset += 2;
    if response.len() < offset + sig_size {
        return Err(KeyStoreError::Internal(
            "Sign response: sig truncated".into(),
        ));
    }

    Ok(response[offset..offset + sig_size].to_vec())
}

/// Build TPM2_FlushContext command (no sessions required)
fn build_flush_command(handle: u32) -> Vec<u8> {
    let total_size = (TPM2_HEADER_SIZE + 4) as u32;
    let mut cmd = Vec::with_capacity(total_size as usize);
    cmd.extend_from_slice(&TPM2_ST_NO_SESSIONS.to_be_bytes());
    cmd.extend_from_slice(&total_size.to_be_bytes());
    cmd.extend_from_slice(&TPM2_CC_FLUSH_CONTEXT.to_be_bytes());
    cmd.extend_from_slice(&handle.to_be_bytes());
    cmd
}

/// Build TPM2_ReadPublic command
fn build_read_public_command(handle: u32) -> Vec<u8> {
    let total_size = (TPM2_HEADER_SIZE + 4) as u32;
    let mut cmd = Vec::with_capacity(total_size as usize);
    cmd.extend_from_slice(&TPM2_ST_NO_SESSIONS.to_be_bytes());
    cmd.extend_from_slice(&total_size.to_be_bytes());
    cmd.extend_from_slice(&TPM2_CC_READ_PUBLIC.to_be_bytes());
    cmd.extend_from_slice(&handle.to_be_bytes());
    cmd
}

/// Build TPM2_GetCapability command for manufacturer ID
fn build_get_capability_command() -> Vec<u8> {
    let total_size = (TPM2_HEADER_SIZE + 12) as u32;
    let mut cmd = Vec::with_capacity(total_size as usize);
    cmd.extend_from_slice(&TPM2_ST_NO_SESSIONS.to_be_bytes());
    cmd.extend_from_slice(&total_size.to_be_bytes());
    cmd.extend_from_slice(&TPM2_CC_GET_CAPABILITY.to_be_bytes());
    cmd.extend_from_slice(&TPM2_CAP_TPM_PROPERTIES.to_be_bytes());
    cmd.extend_from_slice(&TPM2_PT_MANUFACTURER.to_be_bytes());
    cmd.extend_from_slice(&1u32.to_be_bytes());
    cmd
}

// ============================================================================
// DER Encoding Helpers
// ============================================================================

/// Encode DER length
fn der_encode_length(len: usize) -> Vec<u8> {
    if len < 0x80 {
        vec![len as u8]
    } else if len < 0x100 {
        vec![0x81, len as u8]
    } else {
        vec![0x82, (len >> 8) as u8, len as u8]
    }
}

/// Build DER SEQUENCE
fn der_sequence(contents: &[u8]) -> Vec<u8> {
    let mut out = vec![0x30]; // SEQUENCE tag
    out.extend_from_slice(&der_encode_length(contents.len()));
    out.extend_from_slice(contents);
    out
}

/// Build DER INTEGER from unsigned big-endian bytes
fn der_integer(value: &[u8]) -> Vec<u8> {
    let mut out = vec![0x02]; // INTEGER tag
                              // Strip leading zeros but keep at least one byte
    let trimmed = match value.iter().position(|&b| b != 0) {
        Some(pos) => &value[pos..],
        None => &[0u8],
    };
    // Add padding byte if high bit is set (unsigned)
    if trimmed[0] & 0x80 != 0 {
        out.extend_from_slice(&der_encode_length(trimmed.len() + 1));
        out.push(0x00);
    } else {
        out.extend_from_slice(&der_encode_length(trimmed.len()));
    }
    out.extend_from_slice(trimmed);
    out
}

/// Build DER BIT STRING (with zero unused bits)
fn der_bit_string(contents: &[u8]) -> Vec<u8> {
    let mut out = vec![0x03]; // BIT STRING tag
    out.extend_from_slice(&der_encode_length(contents.len() + 1));
    out.push(0x00); // zero unused bits
    out.extend_from_slice(contents);
    out
}

/// Build DER NULL
fn der_null() -> Vec<u8> {
    vec![0x05, 0x00]
}

/// Convert ECDSA (r, s) to DER-encoded signature
fn ecdsa_rs_to_der(r: &[u8], s: &[u8]) -> Vec<u8> {
    let r_int = der_integer(r);
    let s_int = der_integer(s);
    let mut inner = Vec::with_capacity(r_int.len() + s_int.len());
    inner.extend_from_slice(&r_int);
    inner.extend_from_slice(&s_int);
    der_sequence(&inner)
}

/// Convert EC point (x, y) to SPKI DER
fn ec_point_to_spki_der(curve_oid: &[u8], x: &[u8], y: &[u8]) -> Vec<u8> {
    // AlgorithmIdentifier: SEQUENCE { ecPublicKey OID, curve OID }
    let mut algo_contents = Vec::new();
    algo_contents.extend_from_slice(OID_EC_PUBLIC_KEY);
    algo_contents.extend_from_slice(curve_oid);
    let algo_id = der_sequence(&algo_contents);

    // Uncompressed point: 0x04 || x || y
    let mut point = Vec::with_capacity(1 + x.len() + y.len());
    point.push(0x04);
    point.extend_from_slice(x);
    point.extend_from_slice(y);
    let public_key = der_bit_string(&point);

    // SubjectPublicKeyInfo: SEQUENCE { AlgorithmIdentifier, BIT STRING }
    let mut spki_contents = Vec::new();
    spki_contents.extend_from_slice(&algo_id);
    spki_contents.extend_from_slice(&public_key);
    der_sequence(&spki_contents)
}

/// Convert RSA modulus + exponent to SPKI DER
fn rsa_to_spki_der(modulus: &[u8], exponent: u32) -> Vec<u8> {
    let exp_bytes = exponent.to_be_bytes();
    // Trim leading zeros from exponent
    let exp_trimmed = match exp_bytes.iter().position(|&b| b != 0) {
        Some(pos) => &exp_bytes[pos..],
        None => &[0u8],
    };

    // RSAPublicKey: SEQUENCE { INTEGER n, INTEGER e }
    let n_int = der_integer(modulus);
    let e_int = der_integer(exp_trimmed);
    let mut rsa_key = Vec::new();
    rsa_key.extend_from_slice(&n_int);
    rsa_key.extend_from_slice(&e_int);
    let rsa_seq = der_sequence(&rsa_key);
    let rsa_bits = der_bit_string(&rsa_seq);

    // AlgorithmIdentifier: SEQUENCE { rsaEncryption OID, NULL }
    let mut algo_contents = Vec::new();
    algo_contents.extend_from_slice(OID_RSA_ENCRYPTION);
    algo_contents.extend_from_slice(&der_null());
    let algo_id = der_sequence(&algo_contents);

    // SubjectPublicKeyInfo
    let mut spki_contents = Vec::new();
    spki_contents.extend_from_slice(&algo_id);
    spki_contents.extend_from_slice(&rsa_bits);
    der_sequence(&spki_contents)
}

// ============================================================================
// TPM Public Area Parsing
// ============================================================================

/// Parsed public key material from TPM2B_PUBLIC
#[derive(Debug)]
enum TpmPublicKey {
    Ecc {
        curve: u16,
        x: Vec<u8>,
        y: Vec<u8>,
    },
    Rsa {
        _key_bits: u16,
        exponent: u32,
        modulus: Vec<u8>,
    },
}

/// Parse TPMT_PUBLIC from a TPM2B_PUBLIC blob to extract the public key
///
/// TPM2B_PUBLIC layout: size(2) + TPMT_PUBLIC
/// TPMT_PUBLIC layout: type(2) + nameAlg(2) + objectAttributes(4) + authPolicy(TPM2B) + params + unique
fn parse_tpm_public(public_blob: &[u8]) -> KeyStoreResult<TpmPublicKey> {
    if public_blob.len() < 2 {
        return Err(KeyStoreError::Internal(
            "Public blob too short for size".into(),
        ));
    }
    let pub_size = u16::from_be_bytes([public_blob[0], public_blob[1]]) as usize;
    if public_blob.len() < 2 + pub_size {
        return Err(KeyStoreError::Internal("Public blob truncated".into()));
    }
    let data = &public_blob[2..2 + pub_size];
    if data.len() < 10 {
        return Err(KeyStoreError::Internal("TPMT_PUBLIC too short".into()));
    }

    let alg_type = u16::from_be_bytes([data[0], data[1]]);
    // nameAlg at [2..4], objectAttributes at [4..8]
    let mut offset = 8;

    // authPolicy: TPM2B_DIGEST
    if data.len() < offset + 2 {
        return Err(KeyStoreError::Internal("Missing authPolicy".into()));
    }
    let auth_size = u16::from_be_bytes([data[offset], data[offset + 1]]) as usize;
    offset += 2 + auth_size;

    match alg_type {
        TPM2_ALG_ECC => {
            // TPMS_ECC_PARMS: symmetric(2) + scheme(2+2) + curveID(2) + kdf(2)
            if data.len() < offset + 10 {
                return Err(KeyStoreError::Internal("ECC params too short".into()));
            }
            offset += 2; // symmetric (NULL = 2 bytes)
            offset += 4; // scheme (alg + hash = 4 bytes)
            let curve = u16::from_be_bytes([data[offset], data[offset + 1]]);
            offset += 2;
            offset += 2; // kdf (NULL = 2 bytes)

            // unique: TPMS_ECC_POINT { x: TPM2B, y: TPM2B }
            if data.len() < offset + 2 {
                return Err(KeyStoreError::Internal("Missing x size".into()));
            }
            let x_size = u16::from_be_bytes([data[offset], data[offset + 1]]) as usize;
            offset += 2;
            if data.len() < offset + x_size + 2 {
                return Err(KeyStoreError::Internal("Missing x data or y size".into()));
            }
            let x = data[offset..offset + x_size].to_vec();
            offset += x_size;

            let y_size = u16::from_be_bytes([data[offset], data[offset + 1]]) as usize;
            offset += 2;
            if data.len() < offset + y_size {
                return Err(KeyStoreError::Internal("Missing y data".into()));
            }
            let y = data[offset..offset + y_size].to_vec();

            Ok(TpmPublicKey::Ecc { curve, x, y })
        }
        TPM2_ALG_RSA => {
            // TPMS_RSA_PARMS: symmetric(2) + scheme(2+2) + keyBits(2) + exponent(4)
            if data.len() < offset + 12 {
                return Err(KeyStoreError::Internal("RSA params too short".into()));
            }
            offset += 2; // symmetric (NULL)
            offset += 4; // scheme (alg + hash)
            let key_bits = u16::from_be_bytes([data[offset], data[offset + 1]]);
            offset += 2;
            let exponent = u32::from_be_bytes([
                data[offset],
                data[offset + 1],
                data[offset + 2],
                data[offset + 3],
            ]);
            let exponent = if exponent == 0 { 65537 } else { exponent };
            offset += 4;

            // unique: TPM2B_PUBLIC_KEY_RSA
            if data.len() < offset + 2 {
                return Err(KeyStoreError::Internal("Missing modulus size".into()));
            }
            let mod_size = u16::from_be_bytes([data[offset], data[offset + 1]]) as usize;
            offset += 2;
            if data.len() < offset + mod_size {
                return Err(KeyStoreError::Internal("Modulus truncated".into()));
            }
            let modulus = data[offset..offset + mod_size].to_vec();

            Ok(TpmPublicKey::Rsa {
                _key_bits: key_bits,
                exponent,
                modulus,
            })
        }
        _ => Err(KeyStoreError::Internal(format!(
            "Unsupported TPM key type: 0x{:04X}",
            alg_type
        ))),
    }
}

/// Convert TpmPublicKey to SPKI DER
fn tpm_public_to_spki_der(public: &TpmPublicKey) -> KeyStoreResult<Vec<u8>> {
    match public {
        TpmPublicKey::Ecc { curve, x, y } => {
            let curve_oid = match *curve {
                TPM2_ECC_NIST_P256 => OID_SECP256R1,
                TPM2_ECC_NIST_P384 => OID_SECP384R1,
                _ => {
                    return Err(KeyStoreError::Internal(format!(
                        "Unsupported TPM curve: 0x{:04X}",
                        curve
                    )))
                }
            };
            Ok(ec_point_to_spki_der(curve_oid, x, y))
        }
        TpmPublicKey::Rsa {
            exponent, modulus, ..
        } => Ok(rsa_to_spki_der(modulus, *exponent)),
    }
}

// ============================================================================
// Key Metadata (persisted alongside blobs)
// ============================================================================

/// Metadata for a TPM-stored key
#[derive(Debug, Clone, Serialize, Deserialize)]
struct TpmKeyMeta {
    /// Key identifier
    key_id: String,
    /// Human-readable label
    label: String,
    /// Key algorithm specification
    spec: KeySpec,
    /// Creation timestamp
    created_at: chrono::DateTime<chrono::Utc>,
    /// SHA-256 fingerprint of public key
    fingerprint: String,
}

// ============================================================================
// TpmKeyStore
// ============================================================================

/// TPM 2.0 key store using raw device I/O
///
/// Keys are generated inside the TPM under the Storage Root Key (SRK).
/// Private keys never leave the TPM in cleartext. Wrapped key blobs
/// are stored on disk for persistence between restarts.
pub struct TpmKeyStore {
    /// TPM device file handle (serialized via Mutex)
    device: Mutex<File>,
    /// SRK persistent handle
    srk_handle: u32,
    /// Directory for storing wrapped key blobs and metadata
    blob_dir: PathBuf,
    /// Loaded key metadata (key_id → metadata + blob paths)
    keys: Mutex<HashMap<KeyId, TpmKeyEntry>>,
}

/// Internal entry for a loaded key
struct TpmKeyEntry {
    /// Key metadata
    meta: TpmKeyMeta,
    /// Path to the wrapped key blob file
    blob_path: PathBuf,
    /// Path to the metadata JSON file
    meta_path: PathBuf,
}

impl TpmKeyStore {
    /// Create a new TPM key store
    ///
    /// # Arguments
    /// * `device_path` - Path to TPM device (e.g., `/dev/tpmrm0`)
    /// * `srk_handle` - Persistent handle for the Storage Root Key (default: `0x81000001`)
    /// * `blob_dir` - Directory to store wrapped key blobs and metadata
    pub fn new(device_path: &str, srk_handle: u32, blob_dir: &Path) -> KeyStoreResult<Self> {
        let device = open_tpm_device(device_path)?;

        // Create blob directory if it doesn't exist
        fs::create_dir_all(blob_dir).map_err(|e| {
            KeyStoreError::Internal(format!("Failed to create blob directory: {}", e))
        })?;

        let store = Self {
            device: Mutex::new(device),
            srk_handle,
            blob_dir: blob_dir.to_path_buf(),
            keys: Mutex::new(HashMap::new()),
        };

        // Verify SRK is accessible
        store.verify_srk()?;

        // Load existing key metadata from disk
        store.load_keys_from_disk()?;

        Ok(store)
    }

    /// Find and open the first available TPM device with default SRK
    pub fn auto_detect(blob_dir: &Path) -> KeyStoreResult<Self> {
        let device_path = TPM_DEVICE_PATHS
            .iter()
            .copied()
            .find(|p| Path::new(p).exists())
            .ok_or_else(|| {
                KeyStoreError::ConnectionError(format!(
                    "No TPM device found (checked: {})",
                    TPM_DEVICE_PATHS.join(", ")
                ))
            })?;

        Self::new(device_path, DEFAULT_SRK_HANDLE, blob_dir)
    }

    /// Verify the SRK is accessible via TPM2_ReadPublic
    fn verify_srk(&self) -> KeyStoreResult<()> {
        let mut device = self
            .device
            .lock()
            .map_err(|_| KeyStoreError::Internal("TPM device lock poisoned".into()))?;

        let cmd = build_read_public_command(self.srk_handle);
        let response = execute_command(&mut device, &cmd)?;
        check_response(&response, "TPM2_ReadPublic(SRK)")?;
        Ok(())
    }

    /// Load key metadata from disk
    fn load_keys_from_disk(&self) -> KeyStoreResult<()> {
        let mut keys = self
            .keys
            .lock()
            .map_err(|_| KeyStoreError::Internal("Keys lock poisoned".into()))?;

        let entries = match fs::read_dir(&self.blob_dir) {
            Ok(entries) => entries,
            Err(_) => return Ok(()), // Directory doesn't exist or unreadable
        };

        for entry in entries.flatten() {
            let path = entry.path();
            if path.extension().and_then(|e| e.to_str()) != Some("json") {
                continue;
            }

            // Read metadata
            let json = match fs::read_to_string(&path) {
                Ok(j) => j,
                Err(_) => continue,
            };
            let meta: TpmKeyMeta = match serde_json::from_str(&json) {
                Ok(m) => m,
                Err(_) => continue,
            };

            // Verify blob file exists
            let blob_path = path.with_extension("blob");
            if !blob_path.exists() {
                continue;
            }

            let key_id = KeyId::new(&meta.key_id);
            keys.insert(
                key_id,
                TpmKeyEntry {
                    meta,
                    blob_path,
                    meta_path: path,
                },
            );
        }

        Ok(())
    }

    /// Generate a unique key ID
    fn generate_key_id(label: &str) -> KeyId {
        use rand::RngCore;
        let mut bytes = [0u8; 8];
        rand::rngs::OsRng.fill_bytes(&mut bytes);
        KeyId::new(format!("{}-{}", label, hex::encode(bytes)))
    }

    /// Calculate key fingerprint from SPKI DER
    fn calculate_fingerprint(spki_der: &[u8]) -> String {
        digest::sha256(spki_der)
            .iter()
            .map(|b| format!("{:02X}", b))
            .collect::<Vec<_>>()
            .join(":")
    }

    /// Convert KeySpec to TPM parameters: (is_ecc, curve/keybits, hash_alg)
    fn spec_to_tpm_params(spec: KeySpec) -> KeyStoreResult<TpmKeyParams> {
        match spec {
            KeySpec::EcdsaP256 => Ok(TpmKeyParams::Ecc {
                curve: TPM2_ECC_NIST_P256,
                hash_alg: TPM2_ALG_SHA256,
            }),
            KeySpec::EcdsaP384 => Ok(TpmKeyParams::Ecc {
                curve: TPM2_ECC_NIST_P384,
                hash_alg: TPM2_ALG_SHA384,
            }),
            KeySpec::Rsa2048 => Ok(TpmKeyParams::Rsa {
                key_bits: 2048,
                hash_alg: TPM2_ALG_SHA256,
            }),
            KeySpec::Rsa3072 => Ok(TpmKeyParams::Rsa {
                key_bits: 3072,
                hash_alg: TPM2_ALG_SHA256,
            }),
            KeySpec::Rsa4096 => Ok(TpmKeyParams::Rsa {
                key_bits: 4096,
                hash_alg: TPM2_ALG_SHA256,
            }),
            #[cfg(feature = "pqc")]
            _ => Err(KeyStoreError::NotSupported(
                "PQC algorithms not supported by TPM 2.0 hardware".into(),
            )),
        }
    }

    /// Load a key into TPM transient memory, execute operation, then flush
    fn with_loaded_key<F, T>(&self, key_id: &KeyId, operation: F) -> KeyStoreResult<T>
    where
        F: FnOnce(&mut File, u32) -> KeyStoreResult<T>,
    {
        let keys = self
            .keys
            .lock()
            .map_err(|_| KeyStoreError::Internal("Keys lock poisoned".into()))?;

        let entry = keys
            .get(key_id)
            .ok_or_else(|| KeyStoreError::KeyNotFound(key_id.to_string()))?;

        // Read blob from disk
        let blob = fs::read(&entry.blob_path)
            .map_err(|e| KeyStoreError::Internal(format!("Failed to read key blob: {}", e)))?;

        // Split blob into private + public parts
        // Blob format: private(TPM2B) + public(TPM2B)
        if blob.len() < 4 {
            return Err(KeyStoreError::Internal("Key blob too short".into()));
        }
        let priv_size = u16::from_be_bytes([blob[0], blob[1]]) as usize;
        let priv_end = 2 + priv_size;
        if blob.len() < priv_end + 2 {
            return Err(KeyStoreError::Internal("Key blob truncated".into()));
        }
        let private_blob = &blob[..priv_end];
        let public_blob = &blob[priv_end..];

        drop(keys); // Release keys lock before acquiring device lock

        let mut device = self
            .device
            .lock()
            .map_err(|_| KeyStoreError::Internal("TPM device lock poisoned".into()))?;

        // TPM2_Load
        let load_cmd = build_load_command(self.srk_handle, private_blob, public_blob);
        let load_response = execute_command(&mut device, &load_cmd)?;
        let handle = parse_load_response(&load_response)?;

        // Execute the operation
        let result = operation(&mut device, handle);

        // Always flush the transient key, even if operation failed
        let flush_cmd = build_flush_command(handle);
        let _ = execute_command(&mut device, &flush_cmd);

        result
    }
}

/// TPM key generation parameters
enum TpmKeyParams {
    Ecc { curve: u16, hash_alg: u16 },
    Rsa { key_bits: u16, hash_alg: u16 },
}

// ============================================================================
// KeyStore Trait Implementation
// ============================================================================

impl KeyStore for TpmKeyStore {
    fn generate_key(&self, label: &str, spec: KeySpec) -> KeyStoreResult<KeyId> {
        let params = Self::spec_to_tpm_params(spec)?;

        let mut device = self
            .device
            .lock()
            .map_err(|_| KeyStoreError::Internal("TPM device lock poisoned".into()))?;

        // Build and execute TPM2_Create
        let cmd = match &params {
            TpmKeyParams::Ecc { curve, hash_alg } => {
                build_create_ecc_command(self.srk_handle, *curve, *hash_alg)
            }
            TpmKeyParams::Rsa { key_bits, .. } => {
                build_create_rsa_command(self.srk_handle, *key_bits)
            }
        };

        let response = execute_command(&mut device, &cmd)?;
        let (out_private, out_public) = parse_create_response(&response)?;

        drop(device); // Release device lock

        // Parse public key for fingerprint
        let tpm_pub = parse_tpm_public(&out_public)?;
        let spki_der = tpm_public_to_spki_der(&tpm_pub)?;
        let fingerprint = Self::calculate_fingerprint(&spki_der);

        // Generate key ID
        let key_id = Self::generate_key_id(label);

        // Save blob to disk (private + public concatenated)
        let blob_path = self.blob_dir.join(format!("{}.blob", key_id.as_str()));
        let meta_path = self.blob_dir.join(format!("{}.json", key_id.as_str()));

        let mut blob = Vec::with_capacity(out_private.len() + out_public.len());
        blob.extend_from_slice(&out_private);
        blob.extend_from_slice(&out_public);

        write_restricted(&blob_path, &blob)
            .map_err(|e| KeyStoreError::Internal(format!("Failed to write key blob: {}", e)))?;

        // Save metadata
        let meta = TpmKeyMeta {
            key_id: key_id.as_str().to_string(),
            label: label.to_string(),
            spec,
            created_at: Utc::now(),
            fingerprint,
        };

        let json = serde_json::to_string_pretty(&meta)
            .map_err(|e| KeyStoreError::Internal(format!("Failed to serialize metadata: {}", e)))?;
        write_restricted(&meta_path, json.as_bytes())
            .map_err(|e| KeyStoreError::Internal(format!("Failed to write metadata: {}", e)))?;

        // Add to in-memory index
        let mut keys = self
            .keys
            .lock()
            .map_err(|_| KeyStoreError::Internal("Keys lock poisoned".into()))?;
        keys.insert(
            key_id.clone(),
            TpmKeyEntry {
                meta,
                blob_path,
                meta_path,
            },
        );

        Ok(key_id)
    }

    fn import_key(&self, _label: &str, _pkcs8_der: &[u8]) -> KeyStoreResult<KeyId> {
        Err(KeyStoreError::NotSupported(
            "Key import not supported for TPM backend. Keys must be generated inside \
             the TPM for maximum security (private key never exists outside the chip)."
                .into(),
        ))
    }

    fn sign(&self, key_id: &KeyId, data: &[u8]) -> KeyStoreResult<Vec<u8>> {
        // Determine the key's algorithm to pick the right hash and signature format
        let (spec, _hash_alg) = {
            let keys = self
                .keys
                .lock()
                .map_err(|_| KeyStoreError::Internal("Keys lock poisoned".into()))?;
            let entry = keys
                .get(key_id)
                .ok_or_else(|| KeyStoreError::KeyNotFound(key_id.to_string()))?;
            (entry.meta.spec, entry.meta.spec)
        };

        let params = Self::spec_to_tpm_params(spec)?;

        // Pre-hash the data
        let (digest, sig_alg, hash_alg, is_ecc) = match params {
            TpmKeyParams::Ecc { hash_alg, .. } => {
                let digest = if hash_alg == TPM2_ALG_SHA384 {
                    digest::sha384(data)
                } else {
                    digest::sha256(data)
                };
                (digest, TPM2_ALG_ECDSA, hash_alg, true)
            }
            TpmKeyParams::Rsa { hash_alg, .. } => {
                let digest = digest::sha256(data);
                (digest, TPM2_ALG_RSASSA, hash_alg, false)
            }
        };

        self.with_loaded_key(key_id, |device, handle| {
            let cmd = build_sign_command(handle, &digest, sig_alg, hash_alg);
            let response = execute_command(device, &cmd)?;
            if is_ecc {
                parse_ecdsa_sign_response(&response)
            } else {
                parse_rsa_sign_response(&response)
            }
        })
    }

    fn verify(&self, _key_id: &KeyId, _data: &[u8], _signature: &[u8]) -> KeyStoreResult<bool> {
        // TPM2_VerifySignature exists but is expensive. For CA use cases,
        // verification is typically done by relying parties, not the CA itself.
        // Use the public key DER with a software verifier instead.
        Err(KeyStoreError::NotSupported(
            "Signature verification should use the public key with a software verifier. \
             TPM verification is not implemented to avoid unnecessary TPM round-trips."
                .into(),
        ))
    }

    fn public_key_der(&self, key_id: &KeyId) -> KeyStoreResult<Vec<u8>> {
        let keys = self
            .keys
            .lock()
            .map_err(|_| KeyStoreError::Internal("Keys lock poisoned".into()))?;

        let entry = keys
            .get(key_id)
            .ok_or_else(|| KeyStoreError::KeyNotFound(key_id.to_string()))?;

        // Read blob and extract public portion
        let blob = fs::read(&entry.blob_path)
            .map_err(|e| KeyStoreError::Internal(format!("Failed to read key blob: {}", e)))?;

        // Skip private part
        if blob.len() < 2 {
            return Err(KeyStoreError::Internal("Blob too short".into()));
        }
        let priv_size = u16::from_be_bytes([blob[0], blob[1]]) as usize;
        let pub_start = 2 + priv_size;
        if blob.len() <= pub_start {
            return Err(KeyStoreError::Internal("No public data in blob".into()));
        }

        let tpm_pub = parse_tpm_public(&blob[pub_start..])?;
        tpm_public_to_spki_der(&tpm_pub)
    }

    fn key_info(&self, key_id: &KeyId) -> KeyStoreResult<StoredKeyInfo> {
        let keys = self
            .keys
            .lock()
            .map_err(|_| KeyStoreError::Internal("Keys lock poisoned".into()))?;

        let entry = keys
            .get(key_id)
            .ok_or_else(|| KeyStoreError::KeyNotFound(key_id.to_string()))?;

        Ok(StoredKeyInfo {
            id: key_id.clone(),
            spec: entry.meta.spec,
            label: entry.meta.label.clone(),
            created_at: entry.meta.created_at,
            exportable: false, // TPM keys are never exportable
            fingerprint: entry.meta.fingerprint.clone(),
        })
    }

    fn list_keys(&self) -> KeyStoreResult<Vec<StoredKeyInfo>> {
        let keys = self
            .keys
            .lock()
            .map_err(|_| KeyStoreError::Internal("Keys lock poisoned".into()))?;

        Ok(keys
            .iter()
            .map(|(key_id, entry)| StoredKeyInfo {
                id: key_id.clone(),
                spec: entry.meta.spec,
                label: entry.meta.label.clone(),
                created_at: entry.meta.created_at,
                exportable: false,
                fingerprint: entry.meta.fingerprint.clone(),
            })
            .collect())
    }

    fn delete_key(&self, key_id: &KeyId) -> KeyStoreResult<()> {
        let mut keys = self
            .keys
            .lock()
            .map_err(|_| KeyStoreError::Internal("Keys lock poisoned".into()))?;

        let entry = keys
            .remove(key_id)
            .ok_or_else(|| KeyStoreError::KeyNotFound(key_id.to_string()))?;

        // Remove files from disk
        let _ = fs::remove_file(&entry.blob_path);
        let _ = fs::remove_file(&entry.meta_path);

        Ok(())
    }

    fn key_exists(&self, key_id: &KeyId) -> bool {
        self.keys
            .lock()
            .map(|keys| keys.contains_key(key_id))
            .unwrap_or(false)
    }

    fn export_private_key(&self, _key_id: &KeyId) -> KeyStoreResult<Zeroizing<Vec<u8>>> {
        Err(KeyStoreError::NotSupported(
            "TPM keys cannot be exported — private key material never leaves the TPM".into(),
        ))
    }

    fn backend_name(&self) -> &'static str {
        "TPM2"
    }

    fn health_check(&self) -> KeyStoreResult<()> {
        let mut device = self
            .device
            .lock()
            .map_err(|_| KeyStoreError::Internal("TPM device lock poisoned".into()))?;

        // TPM2_GetCapability as health probe
        let cmd = build_get_capability_command();
        let response = execute_command(&mut device, &cmd)?;
        check_response(&response, "TPM2_GetCapability")?;

        Ok(())
    }
}

