    #[test]
    fn test_build_empty_password_auth() {
        let auth = build_empty_password_auth();
        assert_eq!(auth.len(), 9);
        // Session handle: TPM_RS_PW
        assert_eq!(&auth[0..4], &TPM_RS_PW.to_be_bytes());
        // Nonce: empty
        assert_eq!(&auth[4..6], &[0x00, 0x00]);
        // Attributes: continueSession
        assert_eq!(auth[6], 0x01);
        // Password: empty
        assert_eq!(&auth[7..9], &[0x00, 0x00]);
    }

    #[test]
    fn test_build_create_ecc_command() {
        let cmd = build_create_ecc_command(DEFAULT_SRK_HANDLE, TPM2_ECC_NIST_P256, TPM2_ALG_SHA256);

        // Check header
        assert_eq!(&cmd[0..2], &TPM2_ST_SESSIONS.to_be_bytes());
        // Check command code
        assert_eq!(&cmd[6..10], &TPM2_CC_CREATE.to_be_bytes());
        // Check parent handle
        assert_eq!(&cmd[10..14], &DEFAULT_SRK_HANDLE.to_be_bytes());
        // Command should be well-formed (size matches actual length)
        let declared_size = u32::from_be_bytes([cmd[2], cmd[3], cmd[4], cmd[5]]) as usize;
        assert_eq!(declared_size, cmd.len());
    }

