    #[test]
    fn test_der_encode_length() {
        assert_eq!(der_encode_length(0), vec![0x00]);
        assert_eq!(der_encode_length(127), vec![0x7F]);
        assert_eq!(der_encode_length(128), vec![0x81, 0x80]);
        assert_eq!(der_encode_length(255), vec![0x81, 0xFF]);
        assert_eq!(der_encode_length(256), vec![0x82, 0x01, 0x00]);
    }

    #[test]
    fn test_der_integer() {
        // Simple value
        assert_eq!(der_integer(&[0x01]), vec![0x02, 0x01, 0x01]);
        // Needs padding (high bit set)
        assert_eq!(der_integer(&[0x80]), vec![0x02, 0x02, 0x00, 0x80]);
        // Leading zeros stripped
        assert_eq!(der_integer(&[0x00, 0x01]), vec![0x02, 0x01, 0x01]);
        // Zero
        assert_eq!(der_integer(&[0x00]), vec![0x02, 0x01, 0x00]);
    }

    #[test]
    fn test_ecdsa_rs_to_der() {
        let r = vec![0x01; 32];
        let s = vec![0x02; 32];
        let der = ecdsa_rs_to_der(&r, &s);

        // Should be SEQUENCE { INTEGER, INTEGER }
        assert_eq!(der[0], 0x30); // SEQUENCE
                                  // First integer
        let r_tag_offset = 2; // after SEQUENCE tag + length
        assert_eq!(der[r_tag_offset], 0x02); // INTEGER tag
    }

    #[test]
    fn test_ec_point_to_spki_der() {
        let x = vec![0x01; 32];
        let y = vec![0x02; 32];
        let spki = ec_point_to_spki_der(OID_SECP256R1, &x, &y);

        // Should start with SEQUENCE tag
        assert_eq!(spki[0], 0x30);
        // Should contain the ecPublicKey OID
        assert!(spki
            .windows(OID_EC_PUBLIC_KEY.len())
            .any(|w| w == OID_EC_PUBLIC_KEY));
    }

    #[test]
    fn test_rsa_to_spki_der() {
        let modulus = vec![0x01; 256]; // 2048-bit modulus
        let spki = rsa_to_spki_der(&modulus, 65537);

        assert_eq!(spki[0], 0x30); // SEQUENCE
        assert!(spki
            .windows(OID_RSA_ENCRYPTION.len())
            .any(|w| w == OID_RSA_ENCRYPTION));
    }

    #[test]
    fn test_parse_tpm_public_ecc() {
        // Construct a minimal TPMT_PUBLIC for ECC P-256
        let mut public_area = Vec::new();
        public_area.extend_from_slice(&TPM2_ALG_ECC.to_be_bytes()); // type
        public_area.extend_from_slice(&TPM2_ALG_SHA256.to_be_bytes()); // nameAlg
        public_area.extend_from_slice(&SIGN_KEY_ATTRS.to_be_bytes()); // objectAttributes
        public_area.extend_from_slice(&0u16.to_be_bytes()); // authPolicy: empty
        public_area.extend_from_slice(&TPM2_ALG_NULL.to_be_bytes()); // symmetric
        public_area.extend_from_slice(&TPM2_ALG_ECDSA.to_be_bytes()); // scheme
        public_area.extend_from_slice(&TPM2_ALG_SHA256.to_be_bytes()); // hashAlg
        public_area.extend_from_slice(&TPM2_ECC_NIST_P256.to_be_bytes()); // curveID
        public_area.extend_from_slice(&TPM2_ALG_NULL.to_be_bytes()); // kdf
                                                                     // unique x (32 bytes)
        public_area.extend_from_slice(&32u16.to_be_bytes());
        public_area.extend_from_slice(&[0xAA; 32]);
        // unique y (32 bytes)
        public_area.extend_from_slice(&32u16.to_be_bytes());
        public_area.extend_from_slice(&[0xBB; 32]);

        // Wrap in TPM2B_PUBLIC
        let mut blob = Vec::new();
        blob.extend_from_slice(&(public_area.len() as u16).to_be_bytes());
        blob.extend_from_slice(&public_area);

        let result = parse_tpm_public(&blob).unwrap();
        match result {
            TpmPublicKey::Ecc { curve, x, y } => {
                assert_eq!(curve, TPM2_ECC_NIST_P256);
                assert_eq!(x.len(), 32);
                assert_eq!(y.len(), 32);
                assert!(x.iter().all(|&b| b == 0xAA));
                assert!(y.iter().all(|&b| b == 0xBB));
            }
            _ => panic!("Expected ECC key"),
        }
    }

    #[test]
    fn test_parse_tpm_public_rsa() {
        let mut public_area = Vec::new();
        public_area.extend_from_slice(&TPM2_ALG_RSA.to_be_bytes()); // type
        public_area.extend_from_slice(&TPM2_ALG_SHA256.to_be_bytes()); // nameAlg
        public_area.extend_from_slice(&SIGN_KEY_ATTRS.to_be_bytes()); // objectAttributes
        public_area.extend_from_slice(&0u16.to_be_bytes()); // authPolicy: empty
        public_area.extend_from_slice(&TPM2_ALG_NULL.to_be_bytes()); // symmetric
        public_area.extend_from_slice(&TPM2_ALG_RSASSA.to_be_bytes()); // scheme
        public_area.extend_from_slice(&TPM2_ALG_SHA256.to_be_bytes()); // hashAlg
        public_area.extend_from_slice(&2048u16.to_be_bytes()); // keyBits
        public_area.extend_from_slice(&0u32.to_be_bytes()); // exponent (default)
                                                            // unique modulus (256 bytes for 2048-bit)
        public_area.extend_from_slice(&256u16.to_be_bytes());
        public_area.extend_from_slice(&[0xCC; 256]);

        let mut blob = Vec::new();
        blob.extend_from_slice(&(public_area.len() as u16).to_be_bytes());
        blob.extend_from_slice(&public_area);

        let result = parse_tpm_public(&blob).unwrap();
        match result {
            TpmPublicKey::Rsa {
                _key_bits,
                exponent,
                modulus,
            } => {
                assert_eq!(_key_bits, 2048);
                assert_eq!(exponent, 65537);
                assert_eq!(modulus.len(), 256);
            }
            _ => panic!("Expected RSA key"),
        }
    }

