    // ========================================================================
    // Integration tests (require a running swtpm or real TPM)
    // ========================================================================

    #[test]
    #[ignore] // Run with: cargo test --features tpm -- --ignored
    fn test_tpm_generate_and_sign() {
        let blob_dir = tempfile::tempdir().unwrap();
        let store = TpmKeyStore::auto_detect(blob_dir.path())
            .expect("TPM not available — install swtpm for testing");

        // Generate a P-256 key
        let key_id = store
            .generate_key("test-p256", KeySpec::EcdsaP256)
            .expect("Key generation failed");

        // Verify key exists
        assert!(store.key_exists(&key_id));

        // Get public key
        let pub_der = store.public_key_der(&key_id).expect("Public key failed");
        assert!(!pub_der.is_empty());

        // Sign data
        let data = b"test data for TPM signing";
        let signature = store.sign(&key_id, data).expect("Signing failed");
        assert!(!signature.is_empty());

        // Get key info
        let info = store.key_info(&key_id).expect("Key info failed");
        assert_eq!(info.spec, KeySpec::EcdsaP256);
        assert!(!info.exportable);

        // Export should fail
        assert!(store.export_private_key(&key_id).is_err());

        // Health check
        assert!(store.health_check().is_ok());

        // Delete key
        store.delete_key(&key_id).expect("Delete failed");
        assert!(!store.key_exists(&key_id));
    }

    #[test]
    #[ignore]
    fn test_tpm_rsa_key() {
        let blob_dir = tempfile::tempdir().unwrap();
        let store = TpmKeyStore::auto_detect(blob_dir.path()).expect("TPM not available");

        let key_id = store
            .generate_key("test-rsa", KeySpec::Rsa2048)
            .expect("RSA key generation failed");

        let data = b"RSA signing test";
        let signature = store.sign(&key_id, data).expect("RSA signing failed");
        assert!(!signature.is_empty());

        store.delete_key(&key_id).unwrap();
    }

    #[test]
    #[ignore]
    fn test_tpm_key_persistence() {
        let blob_dir = tempfile::tempdir().unwrap();

        // Generate a key
        let key_id = {
            let store = TpmKeyStore::auto_detect(blob_dir.path()).expect("TPM not available");
            store
                .generate_key("persist-test", KeySpec::EcdsaP256)
                .expect("Key generation failed")
        };

        // Re-open the store — key should be loaded from disk
        let store = TpmKeyStore::auto_detect(blob_dir.path()).expect("TPM not available");

        assert!(store.key_exists(&key_id));
        let info = store.key_info(&key_id).unwrap();
        assert_eq!(info.spec, KeySpec::EcdsaP256);

        // Should still be able to sign with the persisted key
        let signature = store
            .sign(&key_id, b"persistence test")
            .expect("Signing with persisted key failed");
        assert!(!signature.is_empty());
    }
